func TestProjectRunOutHoursUsesRemainingHeadroom(t *testing.T) {
	now := time.Now().UTC().Truncate(time.Hour)
	buckets := make([]agent.UsageBucket, 24)
	for i := range buckets {
		buckets[i] = agent.UsageBucket{
			Start:  now.Add(time.Duration(i-23) * time.Hour),
			Tokens: 1000 + i*100,
		}
