// filterProviderOutcomes returns outcomes for a given harness within the last windowDays days.
func filterProviderOutcomes(outcomes []agent.RoutingOutcome, harnessName string, now time.Time, windowDays int) []agent.RoutingOutcome {
	cutoff := now.Add(-time.Duration(windowDays) * 24 * time.Hour)
	result := make([]agent.RoutingOutcome, 0)
	for _, o := range outcomes {
		if o.Harness == harnessName && o.ObservedAt.After(cutoff) {
			result = append(result, o)
		}
	}
	return result
}

// computeProviderPerformance computes latency percentiles and success rate from outcomes.
// Returns -1 sentinels when sample_count < 3 per FEAT-014.
func computeProviderPerformance(outcomes []agent.RoutingOutcome) ProviderPerformance {
	perf := ProviderPerformance{
		P50LatencyMS: -1,
		P95LatencyMS: -1,
		SuccessRate:  -1,
		SampleCount:  len(outcomes),
		Window:       "7d",
	}
	if len(outcomes) < 3 {
		return perf
	}
	var successCount int
	latencies := make([]int, 0, len(outcomes))
	for _, o := range outcomes {
		if o.Success {
			successCount++
		}
		latencies = append(latencies, o.LatencyMS)
	}
	perf.SuccessRate = float64(successCount) / float64(len(outcomes))
	sort.Ints(latencies)
	perf.P50LatencyMS = latencies[len(latencies)/2]
	p95Idx := int(float64(len(latencies)-1) * 0.95)
	perf.P95LatencyMS = latencies[p95Idx]
	return perf
}

// collectProviderSignalSources builds the signal_sources array from the quota
// state and metrics presence.
// Defined values per FEAT-014: native-session-jsonl, stats-cache, ddx-metrics, none.
func collectProviderSignalSources(quota *agentlib.QuotaState, hasMetrics bool) []string {
	seen := map[string]bool{}
	result := []string{}
	if quota != nil && quota.Source != "" {
		if enum := signalSourceAPIEnum(quota.Source); enum != "none" {
			seen[enum] = true
			result = append(result, enum)
		}
	}
	if hasMetrics && !seen["ddx-metrics"] {
		result = append(result, "ddx-metrics")
		seen["ddx-metrics"] = true
	}
	if len(result) == 0 {
		result = []string{"none"}
	}
	return result
}

// providerFreshnessTS returns the oldest contributing signal timestamp.
// Returns zero time when no signals exist (caller omits the field per FEAT-014).
func providerFreshnessTS(quota *agentlib.QuotaState, outcomes []agent.RoutingOutcome) time.Time {
	var oldest time.Time
	if quota != nil && !quota.CapturedAt.IsZero() {
		oldest = quota.CapturedAt
	}
	for _, o := range outcomes {
		if oldest.IsZero() || o.ObservedAt.Before(oldest) {
			oldest = o.ObservedAt
		}
	}
	return oldest
}

// providerStatusStrInfo maps a HarnessInfo to the API status string.
func providerStatusStrInfo(info agentlib.HarnessInfo) string {
	if info.Name == "" {
		return "unknown"
	}
	if info.Available {
		return "available"
	}
	if strings.TrimSpace(info.Error) != "" {
		return "unavailable: " + info.Error
	}
	return "unavailable"
}

// providerRequestFitFromInfo returns request_fit from harness routing eligibility.
func providerRequestFitFromInfo(info agentlib.HarnessInfo) string {
	if info.AutoRoutingEligible {
		return "capable"
	}
	return "unknown"
}

// providerAuthStateFromInfo maps the upstream account status directly to the API enum.
func providerAuthStateFromInfo(info agentlib.HarnessInfo) string {
	if info.Account == nil {
		return "unknown"
	}
	switch {
	case info.Account.Unauthenticated:
		return "unauthenticated"
	case info.Account.Authenticated:
		return "authenticated"
	default:
		return "unknown"
	}
}

// quotaHeadroomFromQuotaState maps the upstream quota status directly to the API enum.
func quotaHeadroomFromQuotaState(q *agentlib.QuotaState) string {
	if q == nil {
		return "unknown"
	}
	for _, w := range q.Windows {
		if strings.EqualFold(w.LimitID, "extra") {
			continue
		}
		if strings.EqualFold(w.State, "blocked") {
			return "blocked"
		}
	}
	switch q.Status {
	case "ok", "stale":
		return "ok"
	case "blocked":
		return "blocked"
	default:
		return "unknown"
	}
}

// costClassFromHarnessInfo consumes the upstream cost class directly.
func costClassFromHarnessInfo(info agentlib.HarnessInfo) string {
	if info.CostClass != "" {
		return info.CostClass
	}
	if info.IsLocal {
		return "local"
	}
	if info.IsSubscription {
		return "subscription"
	}
	return "unknown"
}

